var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"여기가...... 관리국 카운터 아카데미인가?","JPN":"ここが……管理局カウンターアカデミー？","ENG":"So... Is this the Administration Counter Academy?","TWN":"這裡就是……管理局制裁者學院嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"듣던 대로 규모가 엄청 크네.","JPN":"聞いていたとおり、規模がとても大きいな。","ENG":"It's as huge as they say.","TWN":"果然跟傳聞一樣，規模龐大啊。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"전에 다니던 학교랑은 비교도 안 되겠어.","JPN":"前の学校とは比べ物にならないや。","ENG":"It makes my old school look like a nursery.","TWN":"跟以前的學校完全沒辦法相比嘛。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어디 보자...... 편입 수속을 하려면 행정실부터 가야겠지?","JPN":"さてと……編入の手続きをするなら事務室に行くべきだよね。","ENG":"Let’s see... I guess I should find the registrar's office to get processed.","TWN":"我看看……要辦入學手續的話，得先去辦公室吧？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"대체 행정실이 어디 있는 거야?","JPN":"いったい事務室はどこにあるの？","ENG":"Where the heck is the office anyway?","TWN":"辦公室到底在哪裡呀？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아무리 찾아도 안 보이잖아.","JPN":"全然見つからない。","ENG":"I can't find it anywhere.","TWN":"怎麼找也找不到啊。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_Q","text":{"KOREA":"저기......","JPN":"あの……","ENG":"Excuse me.","TWN":"那個……"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응?","JPN":"ん？","ENG":"Hm?","TWN":"嗯？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_Q","text":{"KOREA":"노, 놀라게 했다면 미안해.","JPN":"び、びっくりさせたならごめん。","ENG":"S-sorry if I've startled you.","TWN":"如果有嚇到你的話，對不起。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_Q","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_Q","text":{"KOREA":"아까부터 계속 이 주변을 맴돌고 있는 것 같았거든.","JPN":"さっきからこの辺をずっと行ったり来たりしているみたいだったから。","ENG":"It seems You were looking a little lost here for a while.","TWN":"我看你一直在這附近走來走去的。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_Q","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_Q","text":{"KOREA":"혹시...... 뭔가 찾는 거라도 있어?","JPN":"あの……何か探しているの？","ENG":"Are you... looking for something?","TWN":"是不是……在找什麼？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_Q","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 그게 오늘부터 이 학교에 다니게 됐거든.","JPN":"あ、それがね。今日からこの学校に通うことになったの。","ENG":"I'm a new student here.","TWN":"啊，我是今天第一次來報到的。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_Q","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"편입 수속 때문에 행정실에 가야 하는데 아무리 찾아도 안 보여서.","JPN":"編入手続きで事務室に行きたいんだけど、いくら探しても見当たらなくて。","ENG":"I have to go to the registrar's office to process my transfer, but I couldn't find it anywhere.","TWN":"要辦理入學手續，但是一直找不到辦公室在哪裡。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_Q","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"근처에 물어 볼 만한 사람도 없고 말이야.","JPN":"周りに質問できる人もいないし。","ENG":"And I couldn't find anyone around to ask either.","TWN":"周圍也沒人可以問。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_Q","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_Q","text":{"KOREA":"그랬구나......","JPN":"そうだったんだ……","ENG":"Oh, I see...","TWN":"原來如此……"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_Q","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_Q","text":{"KOREA":"여긴 구교사라 평소엔 사람들이 잘 안 오거든.","JPN":"ここは旧校舎だから、普段は人の出入りはないんだ。","ENG":"This is the old part of campus, so most folks don't come here very often.","TWN":"這裡是舊教學樓，平常很少有人來。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_Q","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_Q","text":{"KOREA":"행정실은 여기서 조금 멀어. 내가 길을 알려 줄게.","JPN":"事務室はここからじゃちょっと遠いかな。よかったら僕が案内するよ。","ENG":"The office is pretty far from here. I'll show you the way.","TWN":"辦公室離這裡有些遠，我告訴你怎麼走。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_Q","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"정말이야?","JPN":"本当に？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_Q","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"한참 헤맸는데 고마워. 덕분에 살았어.","JPN":"結構迷っていたから助かるよ。ありがとう。","ENG":"Thanks. I was so lost. You're a lifesaver.","TWN":"我迷路了很久，太謝謝你了。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_Q","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_Q","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_Q","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"왜 그래? 뭐 잊은 일이라도 있어?","JPN":"どうしたの？　何か他の用事でもあるの？","ENG":"What's wrong? Did you forget something?","TWN":"怎麼了？是忘記什麼事了嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_Q","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_Q","text":{"KOREA":"아, 아니. 아무것도 아냐.","JPN":"い、いや。なんでもない。","ENG":"Oh, no. It's nothing.","TWN":"沒、沒什麼。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_Q","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_Q","text":{"KOREA":"그냥...... 누군가에게 도움이 된 건 오랜만이라.","JPN":"ただ……誰かの役に立てたのが久しぶりすぎてね。","ENG":"It's just that... It's been a while since I've been of help to anyone.","TWN":"只是……沒想到我能幫到別人。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_Q","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_Q","text":{"KOREA":"......자네가 유미나로군.","JPN":"……君がヤナギ・ミナだな。","ENG":"So you’re Yoo Mina.","TWN":"……你就是劉米娜。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_Q","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_Q","text":{"KOREA":"이야기는 들었네. 오늘부터 고등부에 편입하기로 했다지.","JPN":"話は聞いている。今日から高等部に編入することにしたらしいな。","ENG":"I've heard about you. You'll be transferring to high school as of today, correct?","TWN":"我聽說過你的事，今天開始到高等部學習是吧。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_Q","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"아카데미에서 카운터 전술학을 가르치는 알렌 버밍엄이라고 하네.","JPN":"アカデミーでカウンター戦術学を教えているアレン・バーミンガムという。","ENG":"I am Allen Birmingham. I teach Counter tactics here.","TWN":"我是在學院指導制裁者戰術學的艾倫·伯明罕。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"앞으로 잘 부탁하지.","JPN":"これからよろしく。","ENG":"I look forward to seeing you in class.","TWN":"以後多多關照嘍。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나도 잘 부탁해, 선생님.","JPN":"こちらこそよろしくね、先生。","ENG":"Likewise, Prof.","TWN":"日後也請多多指教，老師。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어, 내가 뭔가 실수라도 했어?","JPN":"あれ、どうしたの？","ENG":"Um... Did I offend you or anything?","TWN":"呃，我說錯什麼了嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"아니, 예전에 알던 사람과 말투가 닮아서 말이다.","JPN":"いや、昔の知り合いと話し方が似ていてな。","ENG":"Oh, no. It's just that you talk like someone I used to know.","TWN":"沒有。只是你說話的語氣跟我以前認識的人有些像。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"미안하네. 내 착각이었나 보군.","JPN":"すまん、私の勘違いだろう。","ENG":"I'm sorry I must be mistaken.","TWN":"抱歉，應該是我的錯覺吧。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그보다 서류를 보니 태스크포스 컴퍼니에서 용병으로 근무했다지?","JPN":"それより、書類を読んだがタスクフォースカンパニーで傭兵として務めていたようだな。","ENG":"Anyway, I read in your files that you worked as a mercenary for a TASKFORCE company?","TWN":"看你的檔案，你是特遣勢力公司的傭兵？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L46_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"실전 경험도 많고 평가도 나쁘지 않군. 초보자에게는 흔치 않은 일이야.","JPN":"実戦の経験も豊富だし、評価も悪くない。初心者にしては珍しいケースだ。","ENG":"You've got plenty of combat experience under your belt. And with a decent track record too. That's not very common among beginners.","TWN":"有很多實戰經驗，評價也很高。這對新手來說並不常見。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그런데 최근에 공백기가 좀 있더군. 부상이라도 당했던 건가.","JPN":"しかし最近空白期間があったみたいだな。負傷でもしたのか？","ENG":"But I did notice a brief hiatus recently. Were you injured or something?","TWN":"但最近一段時間顯示為空白，是受傷了嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양, 혹시나 해서 말해 두는 건데 리플레이서와 관련된 작전내용은 기밀사항입니다.","JPN":"ミナさん、念のために伝えておきますがリプレイサーに関する作戦内容は機密事項です。","ENG":"Mina, just to be clear... Anything related to your mission against the Replacers is strictly confidential.","TWN":"米娜小姐，我要提醒你一點，有關克隆集團的作戰內容是機密。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"기밀사항? 다른 사람들에게 말하지 말라는 거야?","JPN":"機密事項？　他の人に言っちゃいけないってこと？","ENG":"Confidential? You mean I can't tell other people about it?","TWN":"機密？意思是不能跟別人說？"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네. 공식적으로 리플레이서 킹......","JPN":"はい、正式にリプレイサー・キング……","ENG":"That's correct. Officially, the Replacer King...","TWN":"是的。官方上的說法是克隆·帝皇……"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아니, 도미닉 킹 레지날드 준장은 잠입 작전 중 순직으로 처리되었으니까요.","JPN":"いや、ドミニーク・キング・レジナルド准将は作戦中に殉職したと記録されているのです。","ENG":"I mean, Brigadier General Dominic King Reginald, was killed in the line of duty while under cover.","TWN":"不，多明尼克準將是在潛入作戰中做為因公殉職來處理的……"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"마음에 들지 않더라도 그런 내용을 여기저기 떠벌리고 다닐 수는 없는 법이죠.","JPN":"気に入らなくても、そんな内容を広めるわけにはいきませんから。","ENG":"I know it sucks, but we simply can't go around telling folks about that.","TWN":"你即使不願意，也不能隨意提起這些事情。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"리플레이서와 관련된 미나 양의 작전 기록들은 모두 말소될 겁니다.","JPN":"リプレイサーに関するミナさんの作戦記録もすべて抹消される予定です。","ENG":"Any records of your participation in the Replacer missions will be purged.","TWN":"米娜小姐，與你有關的克隆集團作戰記錄會完全銷毀。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"혹시라도 누군가 그때 일을 묻는다면 뭐라고 대답할지 미리 생각해 두는 것도 좋겠죠.","JPN":"もし誰かにあの時のことを聞かれても、なんて答えるか先に考えておくのもいいでしょう。","ENG":"You may want to come up with a good cover story, in case anyone asks why your record is blank during that time.","TWN":"你最好先想好說詞，以防有人問你當時發生的事情。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 그게 몸이 좀 안 좋아서 어쩔 수 없이......","JPN":"そう、しばらく体調が悪くて仕方なく……","ENG":"Oh, I wasn't feeling so well...","TWN":"啊，那時身體不舒服，所以不得不……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"......그렇군. 하긴 초보자에게 컨디션 관리는 쉽지 않지.","JPN":"……そうか。確かに初心者にとってコンディションの管理は簡単ではないだろう。","ENG":"I see... I suppose beginners may have trouble knowing when to take it easy.","TWN":"……這樣啊。對於新手來說，的確容易出現健康問題。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"하지만 이 정도로도 충분히 대단한 잠재력이야.","JPN":"しかし、これだけでも十分すごい潜在能力だ。","ENG":"But even so, you show great potential.","TWN":"但你表現出的潛能已經十分了不起了。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"아카데미에서 체계적인 전투법을 배운다면 훨씬 더 성장할 수 있을 걸세.","JPN":"アカデミーで理論の伴った戦闘技術を学べば、さらに成長できるはずだ。","ENG":"I'm sure you'll grow even stronger once you've learned a more systematic way to fight at the Academy.","TWN":"在學院中系統性地學習戰鬥方法後，肯定會變的更強。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"미카!","JPN":"ミカ君！","ENG":"Mika!","TWN":"米卡!"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"네! 선생님!","JPN":"はい！　先生！","ENG":"Yes! Mr. Birmingham!","TWN":"是！老師！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L21_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"이쪽은 학생회 서기인 미카 양이라네.","JPN":"こちらは生徒会書記のミカ君だ。","ENG":"This is Mika, the Student Council Clerk.","TWN":"這是學生會的書記員米卡。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그리고 여기 이 학생은 오늘 고등부에 편입한 유미나 양이지.","JPN":"そしてこちらは本日高等部に編入したヤナギ・ミナ君だ。","ENG":"Mika, this is Ms. Yoo Mina. A new student transferred to high school.","TWN":"這位學生是今天入學高等部的劉米娜。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"미카 양이 미나 양에게 학교를 좀 안내해 주면 좋겠군.","JPN":"ミカ君には学校の案内を頼みたい。","ENG":"Perhaps you could show Mina around campus.","TWN":"我希望米卡能給米娜說明一下學校的情況。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"겸사겸사 시뮬레이션 테스트도 진행해 주고.","JPN":"ついでにシミュレーションテストの実施もな。","ENG":"And help her undergo the simulation test while you're at it.","TWN":"順便再完成模擬測試。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"알겠습니다, 맡겨 주세요!","JPN":"わかりました、任せてください！","ENG":"Got it. You can count on me!","TWN":"我知道了，交給我吧！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};